module Xberg
  # Bounding geometry for an OCR element.
  #
  # Supports both axis-aligned rectangles (from Tesseract) and 4-point quadrilaterals
  # (from PaddleOCR and rotated text detection).
  module OcrBoundingGeometry
    extend T::Helpers
    extend T::Sig

    interface!

    # Dispatch from a Hash to the appropriate variant constructor.
    # @param hash [Hash] with discriminator field and variant-specific fields
    # @return [variant_class] an instance of the appropriate variant
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.untyped) }
    def self.from_hash(hash)
      discriminator = hash[:type] || hash["type"]
      case discriminator
      when "rectangle"
        OcrBoundingGeometryRectangle.from_hash(hash)
      when "quadrilateral"
        OcrBoundingGeometryQuadrilateral.from_hash(hash)
      else
        raise "Unknown discriminator: #{discriminator}"
      end
    end
  end
  ## Axis-aligned bounding box (typical for Tesseract output).
  OcrBoundingGeometryRectangle = Data.define(:left, :top, :width, :height) do
    include OcrBoundingGeometry
    extend T::Sig

    # Left x-coordinate in pixels
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def left = super
    # Top y-coordinate in pixels
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def top = super
    # Width in pixels
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def width = super
    # Height in pixels
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def height = super
    sig { returns(T::Boolean) }
    def rectangle? = true
    sig { returns(T::Boolean) }
    def quadrilateral? = false
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(
        left: hash[:left] || hash["left"],
        top: hash[:top] || hash["top"],
        width: hash[:width] || hash["width"],
        height: hash[:height] || hash["height"]
      )
    end
  end
  ## 4-point quadrilateral for rotated/skewed text (PaddleOCR).
  ##
  ## Points are in clockwise order starting from top-left:
  ## `[top_left, top_right, bottom_right, bottom_left]`
  OcrBoundingGeometryQuadrilateral = Data.define(:points) do
    include OcrBoundingGeometry
    extend T::Sig

    # Four corner points as `[[x, y], ...]` in clockwise order
    sig { returns(String) }
    # rubocop:disable Lint/UselessMethodDefinition
    def points = super
    sig { returns(T::Boolean) }
    def rectangle? = false
    sig { returns(T::Boolean) }
    def quadrilateral? = true
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(points: hash[:points] || hash["points"])
    end
  end
end

module Xberg
  # A single line in a unified-diff hunk.
