module Xberg
  # Reason for chunking a document.
  module ChunkingReason
    extend T::Helpers
    extend T::Sig

    interface!

    # Dispatch from a Hash to the appropriate variant constructor.
    # @param hash [Hash] with discriminator field and variant-specific fields
    # @return [variant_class] an instance of the appropriate variant
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.untyped) }
    def self.from_hash(hash)
      discriminator = hash[:type] || hash["type"]
      case discriminator
      when "large_file"
        ChunkingReasonLargeFile.from_hash(hash)
      when "many_pages"
        ChunkingReasonManyPages.from_hash(hash)
      when "ocr_required"
        ChunkingReasonOcrRequired.from_hash(hash)
      when "large_and_many_pages"
        ChunkingReasonLargeAndManyPages.from_hash(hash)
      else
        raise "Unknown discriminator: #{discriminator}"
      end
    end
  end
  ## File exceeds size threshold.
  ChunkingReasonLargeFile = Data.define(:size_bytes, :threshold_bytes) do
    include ChunkingReason
    extend T::Sig

    # Actual size in bytes.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def size_bytes = super
    # Threshold in bytes.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def threshold_bytes = super
    sig { returns(T::Boolean) }
    def large_file? = true
    sig { returns(T::Boolean) }
    def many_pages? = false
    sig { returns(T::Boolean) }
    def ocr_required? = false
    sig { returns(T::Boolean) }
    def large_and_many_pages? = false
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(
        size_bytes: hash[:size_bytes] || hash["size_bytes"],
        threshold_bytes: hash[:threshold_bytes] || hash["threshold_bytes"]
      )
    end
  end
  ## Document has many pages.
  ChunkingReasonManyPages = Data.define(:page_count, :threshold) do
    include ChunkingReason
    extend T::Sig

    # Actual page count.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def page_count = super
    # Threshold page count.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def threshold = super
    sig { returns(T::Boolean) }
    def large_file? = false
    sig { returns(T::Boolean) }
    def many_pages? = true
    sig { returns(T::Boolean) }
    def ocr_required? = false
    sig { returns(T::Boolean) }
    def large_and_many_pages? = false
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(page_count: hash[:page_count] || hash["page_count"], threshold: hash[:threshold] || hash["threshold"])
    end
  end
  ## PDF requires OCR and is large.
  ChunkingReasonOcrRequired = Data.define(:page_count, :force_ocr) do
    include ChunkingReason
    extend T::Sig

    # Page count.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def page_count = super
    # Whether OCR is forced.
    sig { returns(T::Boolean) }
    # rubocop:disable Lint/UselessMethodDefinition
    def force_ocr = super
    sig { returns(T::Boolean) }
    def large_file? = false
    sig { returns(T::Boolean) }
    def many_pages? = false
    sig { returns(T::Boolean) }
    def ocr_required? = true
    sig { returns(T::Boolean) }
    def large_and_many_pages? = false
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(page_count: hash[:page_count] || hash["page_count"], force_ocr: hash[:force_ocr] || hash["force_ocr"])
    end
  end
  ## Both size and page count exceed thresholds.
  ChunkingReasonLargeAndManyPages = Data.define(:size_bytes, :page_count) do
    include ChunkingReason
    extend T::Sig

    # Actual size in bytes.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def size_bytes = super
    # Actual page count.
    sig { returns(Integer) }
    # rubocop:disable Lint/UselessMethodDefinition
    def page_count = super
    sig { returns(T::Boolean) }
    def large_file? = false
    sig { returns(T::Boolean) }
    def many_pages? = false
    sig { returns(T::Boolean) }
    def ocr_required? = false
    sig { returns(T::Boolean) }
    def large_and_many_pages? = true
    # @param hash [Hash] deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(size_bytes: hash[:size_bytes] || hash["size_bytes"], page_count: hash[:page_count] || hash["page_count"])
    end
  end
end

module Xberg
  # Authentication configuration.
  module AuthConfig
    extend T::Helpers
    extend T::Sig

    interface!

    # Dispatch from a Hash to the appropriate variant constructor.
    # @param hash [Hash] with discriminator field and variant-specific fields
    # @return [variant_class] an instance of the appropriate variant
