    def self.from_hash(hash)
      discriminator = hash[:type] || hash["type"]
      case discriminator
      when "basic"
        AuthConfigBasic.from_hash(hash)
      when "bearer"
        AuthConfigBearer.from_hash(hash)
      when "header"
        AuthConfigHeader.from_hash(hash)
      else
        raise "Unknown discriminator: #{discriminator}"
      end
    end
  end
